// ============================================================
//  Servo + LEDs Power-Aware Demo
//  Board: Arduino Uno
// ============================================================
//
//  WIRING TABLE
//  ┌──────────────────┬──────────────┬────────────┬──────────────────────────────────────┐
//  │ Component        │ Power Source │ Arduino Pin│ Notes                                │
//  ├──────────────────┼──────────────┼────────────┼──────────────────────────────────────┤
//  │ Servo (signal)   │ External 5V  │ D9 (PWM)   │ Signal only — power from ext. supply │
//  │ Servo (VCC)      │ External 5V  │ —          │ Direct to ext. 5V rail               │
//  │ Servo (GND)      │ Common GND   │ GND        │ Shared with Arduino GND              │
//  │ LED Red (Left)   │ Arduino 5V   │ D5 (PWM)   │ Via 220Ω resistor → GND              │
//  │ LED Yellow (Ctr) │ Arduino 5V   │ D6 (PWM)   │ Via 220Ω resistor → GND              │
//  │ LED Green (Rgt)  │ Arduino 5V   │ D7         │ Via 220Ω resistor → GND              │
//  │ Pause Button     │ Arduino 5V   │ D2         │ INPUT_PULLUP — other leg → GND       │
//  └──────────────────┴──────────────┴────────────┴──────────────────────────────────────┘
//
//  ⚠️  SAFETY RULES ENFORCED
//  1. Servo VCC goes to the EXTERNAL 5V supply (not Arduino 5V pin).
//     Servo stall current can reach 1A — far beyond the 200mA Arduino rail limit.
//  2. Common ground ties Arduino GND and external supply GND together.
//  3. Each LED has its own 220Ω resistor → I = (5V - 2V) / 220Ω ≈ 13.6mA (safe, <40mA).
//  4. Only the servo SIGNAL wire touches Arduino (D9). No high-current load on any pin.
//  5. Button uses INPUT_PULLUP — no external resistor needed, no floating pin risk.
//
//  POWER BUDGET SUMMARY
//  ┌──────────────────┬──────────┬────────────┬──────────────────────────┐
//  │ Load             │ Voltage  │ Current    │ Source                   │
//  ├──────────────────┼──────────┼────────────┼──────────────────────────┤
//  │ Servo (motor)    │ 5V ext   │ ~500mA peak│ External supply          │
//  │ LED Red          │ 5V Uno   │ ~13.6mA    │ Arduino D5 pin           │
//  │ LED Yellow       │ 5V Uno   │ ~13.6mA    │ Arduino D6 pin           │
//  │ LED Green        │ 5V Uno   │ ~13.6mA    │ Arduino D7 pin           │
//  │ Servo (signal)   │ 5V logic │ <1mA       │ Arduino D9 pin           │
//  │ Arduino board    │ USB/Jack │ ~50mA      │ USB or DC jack           │
//  ├──────────────────┼──────────┼────────────┼──────────────────────────┤
//  │ Arduino rail tot │          │ ~42mA      │ Well under 200mA limit ✓ │
//  │ External rail    │          │ ~500mA     │ Ext. supply handles this │
//  └──────────────────┴──────────┴────────────┴──────────────────────────┘
//
//  WHAT CAN GO WRONG — BEGINNER CHECKLIST
//  □ Powering servo from Arduino 5V pin → brownouts, resets, pin damage.
//  □ Missing common ground → servo behaves erratically or doesn't move.
//  □ No resistor on LED → LED burns out instantly (~30mA on a 2V LED = dead).
//  □ Floating button pin (no pullup/pulldown) → random pause/resume triggers.
//  □ Wiring servo signal to a non-PWM pin → jittery/no movement (use D3/5/6/9/10/11).
//  □ Forgetting #include <Servo.h> → compiler error.
//  □ Calling servo.write() with values outside 0-180 → mechanical binding.
//  □ Driving two loads from the same signal pin → pin current exceeded, pin damaged.
// ============================================================

#include <Servo.h>

// ── Pin assignments ─────────────────────────────────────────
const int PIN_SERVO  = 9;   // PWM — servo signal wire (orange/yellow)
const int PIN_LED_R  = 5;   // Red    LED  — "left"   zone  (0°–59°)
const int PIN_LED_Y  = 6;   // Yellow LED  — "center" zone  (60°–119°)
const int PIN_LED_G  = 7;   // Green  LED  — "right"  zone  (120°–180°)
const int PIN_BTN    = 2;   // Pause button (INPUT_PULLUP)

// ── Motion settings ─────────────────────────────────────────
const int SERVO_MIN  = 0;     // degrees
const int SERVO_MAX  = 180;   // degrees
const int STEP_DEG   = 1;     // degrees per step (smaller = smoother)
const int STEP_MS    = 15;    // ms between steps  (larger = slower sweep)

// ── Runtime state ────────────────────────────────────────────
Servo myServo;

int  currentAngle = 0;        // current servo position
int  direction    = 1;        // +1 = sweeping toward 180°, -1 = back to 0°
bool paused       = false;    // pause flag

// Button debounce
bool     lastBtnState    = HIGH;  // INPUT_PULLUP → HIGH when not pressed
unsigned long lastDebounceTime = 0;
const unsigned long DEBOUNCE_MS = 50;

// ── Helper: light the correct zone LED ───────────────────────
void updateZoneLEDs(int angle) {
  // Turn all off first, then light the one that matches the zone
  digitalWrite(PIN_LED_R, LOW);
  digitalWrite(PIN_LED_Y, LOW);
  digitalWrite(PIN_LED_G, LOW);

  if (angle < 60) {
    digitalWrite(PIN_LED_R, HIGH);   // 0°–59°   → Red   (left zone)
  } else if (angle < 120) {
    digitalWrite(PIN_LED_Y, HIGH);   // 60°–119° → Yellow (center zone)
  } else {
    digitalWrite(PIN_LED_G, HIGH);   // 120°–180°→ Green  (right zone)
  }
}

// ── setup ────────────────────────────────────────────────────
void setup() {
  Serial.begin(9600);
  Serial.println(F("=== Servo + LEDs Power-Aware Demo ==="));
  Serial.println(F("Press button to pause / resume sweep."));

  myServo.attach(PIN_SERVO);
  myServo.write(currentAngle);     // move to start position

  pinMode(PIN_LED_R, OUTPUT);
  pinMode(PIN_LED_Y, OUTPUT);
  pinMode(PIN_LED_G, OUTPUT);
  pinMode(PIN_BTN,   INPUT_PULLUP); // internal pull-up, no external resistor needed

  updateZoneLEDs(currentAngle);    // light the correct LED at startup
}

// ── loop ─────────────────────────────────────────────────────
void loop() {

  // ── 1. Read & debounce the pause button ───────────────────
  bool reading = digitalRead(PIN_BTN);

  if (reading != lastBtnState) {
    lastDebounceTime = millis();   // reset debounce timer on any change
  }

  if ((millis() - lastDebounceTime) > DEBOUNCE_MS) {
    // Stable LOW means button is pressed (INPUT_PULLUP)
    if (reading == LOW) {
      paused = !paused;            // toggle pause
      Serial.print(F("Motion: "));
      Serial.println(paused ? F("PAUSED") : F("RESUMED"));
      delay(300);                  // simple hold-off to avoid repeated toggles
    }
  }

  lastBtnState = reading;

  // ── 2. Advance servo one step if not paused ───────────────
  if (!paused) {
    currentAngle += direction * STEP_DEG;

    // Reverse direction at the endpoints
    if (currentAngle >= SERVO_MAX) {
      currentAngle = SERVO_MAX;
      direction = -1;
      Serial.println(F("→ Reached 180° — reversing"));
    } else if (currentAngle <= SERVO_MIN) {
      currentAngle = SERVO_MIN;
      direction = 1;
      Serial.println(F("← Reached 0° — reversing"));
    }

    myServo.write(currentAngle);    // command the servo
    updateZoneLEDs(currentAngle);   // update zone LEDs

    // Optional: print angle every 10° for debugging
    if (currentAngle % 10 == 0) {
      Serial.print(F("Angle: "));
      Serial.print(currentAngle);
      Serial.println(F("°"));
    }

    delay(STEP_MS);                 // control sweep speed
  }
}

